	private static AlgebraEquivalenceChecker runtimeCheckerWithEmptyCase() {
		CheckOptions options = CheckOptions.builder()
				.boundedCounterexampleSearch(false)
				.addEvaluationCase(EvaluationCase.builder("empty dataset").build())
				.build();
		return new AlgebraEquivalenceChecker(options);
	}

	private static BindingSetAssignment values(String name, Value value) {
		MapBindingSet row = new MapBindingSet();
		row.setBinding(name, value);
		return values(Set.of(name), row);
	}

	private static BindingSetAssignment values(Set<String> declaredNames, MapBindingSet row) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(declaredNames);
		assignment.setBindingSets(List.of(row));
		return assignment;
	}

	private static StatementPattern pattern(String subjectName, IRI predicate, String objectName) {
		return new StatementPattern(
				Var.of(subjectName),
				Var.of("const-" + predicate.stringValue(), predicate),
				Var.of(objectName));
	}
